// // This module is designed to demultiplex a 16-bit data bus into four 16-bit output lines based on a 2-bit select signal.
module mux4to1_16bit (
    input [15:0] data0,
    input [15:0] data1,
    input [15:0] data2,
    input [15:0] data3,
    input [1:0] select,
    output reg [15:0] out
);

always @(*) begin
    case (select)
        2'b00: out = data0;
        2'b01: out = data1;
        2'b10: out = data2;
        2'b11: out = data3;
        default: out = 16'b0; // Default case to avoid latches
    endcase
end

endmodule
